import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Module Dependencies","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Module Dependencies | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/architecture/module-dependencies"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Module Dependencies | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/architecture/module-dependencies"}]]},"headers":[],"relativePath":"architecture/module-dependencies.md","filePath":"architecture/module-dependencies.md","lastUpdated":1784403917000}'),i={name:"architecture/module-dependencies.md"};function s(l,e,d,r,p,c){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="module-dependencies" tabindex="-1">Module Dependencies <a class="header-anchor" href="#module-dependencies" aria-label="Permalink to &quot;Module Dependencies&quot;">​</a></h1><p>Modules may depend on other modules.</p><p>This document defines how dependency relationships are described for product design and future implementation. It is <strong>documentation only</strong> — SaleOS does not yet implement automatic dependency resolution from this convention. Do not treat this page as a shipped runtime feature.</p><h2 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to &quot;Categories&quot;">​</a></h2><p>Dependencies should be categorized as:</p><table tabindex="0"><thead><tr><th>Category</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Required</strong></td><td>The dependent module cannot function correctly without the dependency installed and available</td></tr><tr><td><strong>Optional</strong></td><td>The dependent module works alone; the dependency unlocks extra integrations or features</td></tr></tbody></table><h2 id="commercial-nature-of-a-dependency" tabindex="-1">Commercial nature of a dependency <a class="header-anchor" href="#commercial-nature-of-a-dependency" aria-label="Permalink to &quot;Commercial nature of a dependency&quot;">​</a></h2><p>Independently of required vs optional, a dependency relationship may be:</p><table tabindex="0"><thead><tr><th>Nature</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Free</strong></td><td>The dependency module is free (or included) for the workspace</td></tr><tr><td><strong>Billable</strong></td><td>The dependency module is (or may become) a paid marketplace module</td></tr></tbody></table><p>A required dependency can be free or billable. An optional dependency can be free or billable. Licensing of each module remains independent — see <a href="./module-licensing">Module Licensing</a>.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p>These examples illustrate the intended design language. They are not a commitment that every example is already implemented.</p><h3 id="meetings-→-calendar-required" tabindex="-1">Meetings → Calendar (required) <a class="header-anchor" href="#meetings-→-calendar-required" aria-label="Permalink to &quot;Meetings → Calendar (required)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Meetings</span></span>
<span class="line"><span>  └── depends on Calendar   (required)</span></span></code></pre></div><p>Meeting scheduling assumes calendar concepts (availability, time ranges, calendar views). Meetings should declare Calendar as a <strong>required</strong> dependency.</p><h3 id="payroll-→-hr-required" tabindex="-1">Payroll → HR (required) <a class="header-anchor" href="#payroll-→-hr-required" aria-label="Permalink to &quot;Payroll → HR (required)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Payroll</span></span>
<span class="line"><span>  └── depends on HR         (required)</span></span></code></pre></div><p>Payroll needs employee and employment records from HR. Payroll should not re-implement HR domain logic.</p><h3 id="accounting-→-inventory-optional" tabindex="-1">Accounting → Inventory (optional) <a class="header-anchor" href="#accounting-→-inventory-optional" aria-label="Permalink to &quot;Accounting → Inventory (optional)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Accounting</span></span>
<span class="line"><span>  └── may depend on Inventory   (optional)</span></span></code></pre></div><p>Accounting can operate without Inventory. When Inventory is installed, Accounting may optionally integrate stock valuations or COGS-related flows through contracts/services.</p><h3 id="ai-→-domain-modules-optional" tabindex="-1">AI → domain modules (optional) <a class="header-anchor" href="#ai-→-domain-modules-optional" aria-label="Permalink to &quot;AI → domain modules (optional)&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI</span></span>
<span class="line"><span>  ├── may optionally integrate with Leads</span></span>
<span class="line"><span>  ├── may optionally integrate with Tasks</span></span>
<span class="line"><span>  ├── may optionally integrate with CRM (Contacts, Companies, …)</span></span>
<span class="line"><span>  └── … other domain modules as needed</span></span></code></pre></div><p>AI Integration is planned as a cross-cutting capability. Integrations with Leads, Tasks, CRM, and similar modules should be <strong>optional</strong> — AI must not require every domain module to be installed.</p><h2 id="design-rules" tabindex="-1">Design rules <a class="header-anchor" href="#design-rules" aria-label="Permalink to &quot;Design rules&quot;">​</a></h2><p>When designing a new module:</p><ol><li>List <strong>required</strong> dependencies explicitly in the module’s documentation.</li><li>List <strong>optional</strong> integrations separately so install and licensing expectations stay clear.</li><li>Keep business logic inside the owning module; call dependents through contracts/services only (<a href="./module-architecture">Module Architecture</a>).</li><li>Do not assume a dependency is always present unless it is marked <strong>required</strong> and the platform later enforces that rule.</li><li>Do not implement dependency resolution in application code based on this document alone — that remains future work.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./module-architecture">Module Architecture</a></li><li><a href="./module-licensing">Module Licensing</a></li><li><a href="/getting-started/product-roadmap">Product Roadmap</a> (Calendar, Meetings, AI)</li><li><a href="/developer-guide/entitlements">Entitlements</a></li></ul>`,29)])])}const m=a(i,[["render",s]]);export{h as __pageData,m as default};
